var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"고민 상담이요?","JPN":"お悩み相談ですか？","ENG":"You want me to do counseling for customers?","TWN":"心理諮商嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"응, 가게를 찾아오는 손님들 중엔 마음의 위로가 필요해서 오는 사람들도 있거든.","JPN":"ええ、店に訪れるお客さんの中には、心の癒しを求めて来る人もいるのよ。","ENG":"Yes. Some of our customers come here, seeking comfort.","TWN":"對，來到店裡的客人中，有些是因為想要得到心靈的慰藉。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"바텐딩 기술도 물론 중요하지만, 우리 가게에서 제일 우선시해야 하는 건 손님의 고민을 잘 들어주는 거야.","JPN":"バーテンディングの技術ももちろん大事だけど、\\nうちの店で一番優先すべき仕事はお客さんの悩みをよく聞いてあげることよ。","ENG":"Bartending skills are important, but in my bar, they're not as important as listening skills.","TWN":"調酒技術固然重要，但在我們店裡，最重要的是聆聽客人的煩惱。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"제가… 그런 걸 할 수 있을까요?","JPN":"私に……そんなことができるのでしょうか？","ENG":"But... I don't know if I can give good advice.","TWN":"我…做得到嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후훗, 물론이지.","JPN":"ふふっ、もちろん。","ENG":"Hah hah. Yes, you can.","TWN":"呵呵，那當然囉！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"상담이라고 거창하게 말하긴 했지만, 반드시 정답을 제시해 줄 필요는 없어.","JPN":"相談なんておおげさに言ってしまったけれど、\\n必ずしも正解を提示する必要はないわ。","ENG":"Even though I said counseling, you don't have to give them solutions.","TWN":"諮商聽起來好像很專業，但其實不是一定要給出什麼答案來。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그 사람의 마음에 공감해준다는 제스처 자체가 중요한 거니까 말이야.","JPN":"その人の心に共感しているというジェスチャー自体が大事なんだから。","ENG":"They just want you to listen and emphasize with them, that's all.","TWN":"重點透過肢體或表情，來表達你是同理對方的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네! 그 정도라면 저에게 맡겨주세요!","JPN":"はい！　それくらいなら私に任せてください！","ENG":"Sure, I think I can do that.","TWN":"好！這個我應該做得到！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"으흑… 흐윽… 나쁜 놈! 내가 얼마나 잘 해줬는데…","JPN":"うふっ……ううっ……最低な男！　私がどれだけよくしてあげたか……","ENG":"*Sob* That jerk! I treated him like a prince!","TWN":"嗚嗚…嗚嗚…該死的渣男！虧我對你那麼好…"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"자 자, 진정하고 한잔하세요.","JPN":"まあまあ、落ち着いて一杯飲みましょう。","ENG":"Come on, stop crying and drink this.","TWN":"來吧，喝一杯，平復一下心情～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L15_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"너무 미운데… 나쁜 놈인데… 자꾸 생각나는 거 있죠?","JPN":"憎いし……悪い男なのに……どうしても思い出してしまうんです。","ENG":"I hate him so much, and yet, I can't stop thinking about him.","TWN":"他那麼過分…那麼可惡…為什麼我還是一直會想起他？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"으음, 많이 힘드시겠어요.","JPN":"それは本当に辛いですね。","ENG":"Mm, that must be hard.","TWN":"我懂我懂，很痛苦對吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(으아, 실연이라니… 저에겐 공감하기 어려운 주제네요.)","JPN":"(うわあ、失恋ですか……私には共感しにくいテーマですね。)","ENG":"(Err, relationship problems... I don't know how to react...)","TWN":"(哎呀，這次是失戀…這個話題對我來說有點困難。)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"(그래도 어떻게든 되겠죠! 중요한 건 제스처니까요!)","JPN":"(でもなんとかなるでしょう！　大事なのはジェスチャーですから！)","ENG":"(But I'll try! What matters is that I listen!)","TWN":"(不過應該OK吧？反正重點是肢體跟表情！)"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L21_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"흑… 잊어버리고 싶은데… 너무 괴롭네요… 저는 어떻게 해야 좋을까요?","JPN":"ぐすん……忘れたいのに……辛すぎる……私はどうすればいいですか？","ENG":"*Sniffle* I want to forget him, but I can't... What do I do?","TWN":"嗚嗚…我好想忘了他…真的好痛苦…我該怎麼辦？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"<color=#ffd34c>네 이웃을 네 몸과 같이 사랑하라</color>는 말 들어보셨나요?","JPN":"<color=#ffd34c>「あなたの隣人をあなた自身のように愛せよ」</color>という言葉を知っていますか？","ENG":"Have you heard of the phrase, \\"<color=#ffd34c>Love thy neighbor as thyself</color>?\\"","TWN":"<color=#ffd34c>要愛鄰舍如同自己</color>，這句話你聽過嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"네……? 갑자기 그게 무슨……?","JPN":"はい……？　それはどういう意味ですか……？","ENG":"Huh? What does that have to do with me?","TWN":"什麼……？這什麼意思……？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그, 그러니까…….","JPN":"え、ええっと……","ENG":"S-so...","TWN":"這句話的意思就是……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그 분이 당신의 사랑을 받아주지 않았다고 해서, 당신이 사랑받지 못할 존재라는 뜻은 아니랍니다.","JPN":"その方があなたの愛を受け入れてくれないからって、\\nあなたが愛されない存在というわけではありません。","ENG":"Just because he doesn't love you, it doesn't mean you can't be loved by anyone.","TWN":"就算對方不接受你的愛，但這並不表示你不值得被愛。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"훌쩍… 정말 그럴까요?","JPN":"くすん……本当にそうでしょうか？","ENG":"*Sniffle* You think so?","TWN":"嗚嗚…是真的嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"물론이죠! 세상 모든 남자들이 당신을 저버린다 해도, 신께서는 변함없이 당신을 사랑하시니까요!","JPN":"もちろんです！　この世のすべての男性があなたを見捨てたとしても、\\n神様は変わらずあなたを愛していますから！","ENG":"Absolutely! Even if every man in the world betrays you, God will love you, no matter what!","TWN":"當然囉！就算全世界的男人都背叛你，但神對你的愛是永遠不會改變的！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"클레임이 들어왔어.","JPN":"クレームが寄せられたわ。","ENG":"We've got a complaint.","TWN":"我收到客訴，"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"손님이 단단히 화가 났던데?","JPN":"お客さんがずいぶんとご立腹のようだけど？","ENG":"She's pretty angry.","TWN":"客人好像很生氣的樣子？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"죄, 죄송해요! 경험도 없는 제가 주제넘게 참견했나 봐요!","JPN":"ご、ごめんなさい！　恋愛経験もないくせに私が偉そうに言っちゃって……","ENG":"I-I'm sorry! I shouldn't have talked about something I wasn't experienced in!","TWN":"抱…抱歉！我一個母胎單身的人，有什麼資格插嘴戀愛的事！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"음? 경험이 없다고?","JPN":"うん？　経験がないの？","ENG":"Mm? Something you weren't experienced in?","TWN":"嗯？你母胎單身嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L40_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"니콜 양은 그럼 사랑도 연애도 해 본 적 없는 거야?","JPN":"ニコルちゃんって片思いとか恋愛もしたことないの？","ENG":"Nicole, you've never been in love? No boyfriend?","TWN":"所以你從來沒有談過戀愛嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L41_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? …네.","JPN":"え？　……はい。","ENG":"Huh? ... No.","TWN":"蛤？…對。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"신기하네. 그 외모로 숙맥이라니.","JPN":"意外だわ。その顔でウブだなんて。","ENG":"Wow. You're so beautiful, and yet inexperienced.","TWN":"這麼奇妙，長這麼漂亮都沒人追？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"무슨 남자 하나 없는 산골 수도원에서 자라기라도 한 거야?","JPN":"男が一人もいない山奥の修道院育ちとか？","ENG":"Did you grow up in some monastery on a mountainside, where there were no men at all?","TWN":"你是在全是女人的深山修道院長大的嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? 어떻게 그걸……","JPN":"えっ？　どうしてそれを……","ENG":"Huh? How did you...","TWN":"嗯？你怎麼會知……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네에?!","JPN":"ええっ！？","ENG":"Pardon?","TWN":"什麼？！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후훗, 미안. 농담이 과했네.","JPN":"ふふっ、ごめんなさいね。冗談が過ぎたわ。","ENG":"Hah hah. Sorry, I meant that as a joke.","TWN":"呵呵～抱歉，玩笑開過頭了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L49_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"하지만 말이지. 사랑이란 게 꼭 연애를 해 봐야 알 수 있는 건 아니야.","JPN":"でもね、愛というのは必ずしも恋愛によってわかるものじゃないの。","ENG":"But you don't have to be in love to know what love is.","TWN":"不過，誰說一定要談過戀愛，才能知道什麼是愛。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L50_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"굳이 남자랑 사귀지 않아도, 사랑을 배울 수 있는 법이 있거든.","JPN":"別に男と付き合わなくても、愛を学ぶ方法はあるわ。","ENG":"There's a way to learn about it without having to go out with a man.","TWN":"就算不跟男人談戀愛，也是有方法可以學習愛的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L1_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그, 그런가요? 하지만 어떻게요?","JPN":"そ、そうなんですか？　でも、どうやって？","ENG":"R-really? But how?","TWN":"是嗎？怎麼說呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L2_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"흐음……. 여기선 알려 주기 어려운데.","JPN":"うーん……ここで教えるのは難しいわね。","ENG":"Hmm... I can't tell you here.","TWN":"嗯……在這裡不好說。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L3_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"이렇게 된 이상 나만의 특별한 장소로 안내해 줘야겠네.","JPN":"こうなった以上、アタシだけの特別な場所に案内してあげないとね。","ENG":"I guess I have no choice but to guide you to my special place.","TWN":"我帶你去我的秘密基地好好說吧！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"특별한 장소……? 어떤 곳인가요?","JPN":"特別な場所……？　どんな場所ですか？","ENG":"Your special place? What kind of place is it?","TWN":"你的秘密基地……？那是哪裡？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"우후훗. 니콜 양이 모르는 사랑에 대한 것들로 가득한 곳이지.","JPN":"うふふ。ニコルちゃんが知らない、愛についてのことでいっぱいな場所よ。","ENG":"Hah hah. It's the kind of place that can teach you what love is.","TWN":"呵呵呵，那是個充滿愛的地方喔～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"내 전용 컬렉션도 있으니까 기대해도 좋아.","JPN":"アタシの専用コレクションもあるから楽しみにしてて。","ENG":"It also houses my special collection. You won't be disappointed.","TWN":"裡面還有我個人的收藏，敬請期待～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"컬렉션?","JPN":"コレクション？","ENG":"Collection of what?","TWN":"收藏？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"응. 나만 믿고 따라와. 좋은 걸 잔뜩 가르쳐 줄게.","JPN":"そうよ。お姉ちゃんだけ信じてついて来なさい。\\nイイコトをいっぱい教えてあげる。","ENG":"Just trust me and follow. I'll show you a good time.","TWN":"對啊，跟我來，姊姊教你什麼是愛！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네? 우왓! 자, 잠깐만…!","JPN":"はい？　うわっ！　ちょ、ちょっと待って……！","ENG":"What? Wah! W-wait!","TWN":"蛤？哎呀！先…先等一下…！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_FOOTSTEP_WALK_02"},{"id":"L17_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그래서, 소감은 어땠어?","JPN":"で、感想はどう？","ENG":"So, what do you think?","TWN":"怎麼樣，有什麼感想？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"괴, 굉장했어요. 남자와 사귀지 않고도 이렇게 많은 체험을 할 수 있다니…….","JPN":"す、すごかったです。男性と付き合わなくても\\nこんなにたくさんの体験ができるなんて……","ENG":"I-it was incredible. I've learned so much about romance and relationships without actually going out with a man.","TWN":"好…好厲害！原來就算不跟男人交往，也有這麼多可以體驗的……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"순정만화라는 건 굉장하네요!","JPN":"少女漫画ってすごいですね！","ENG":"Romance comics are awesome!","TWN":"少女漫畫好厲害！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L20_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"후훗, 그렇지?","JPN":"フフッ、そうでしょう？","ENG":"Hah hah. I know, right?","TWN":"呵呵，是不是！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L21_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"더 읽고 싶은 게 있으면 언제든지 찾아와.","JPN":"他にも読みたいものがあればいつでも来てね。","ENG":"You're welcome anytime if you want to read more books.","TWN":"只要是你想看的時候，歡迎隨時過來～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네! 감사해요!","JPN":"はい！　ありがとうございます！","ENG":"Okay! Thank you!","TWN":"好！謝謝你！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L26_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"훌쩍… 고마워요, 니콜 씨. 위로가 됐어요.","JPN":"ぐすん……ありがとうございます、ニコルさん。気持ちが落ち着きました。","ENG":"*Sniffle* Thank you, Nicole. That means a lot to me.","TWN":"嗚嗚…謝謝你，妮可，我覺得心情好多了。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그렇다면 다행이네요.","JPN":"それはよかったです。","ENG":"I'm glad to hear that.","TWN":"那就好～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"니콜 씨는 정말 연애에 대해 잘 아는 것 같아요. 분명 수많은 멋진 남자 분들과 사귀어 본 거죠?","JPN":"ニコルさんは本当に恋愛について詳しいんですね。\\nきっとたくさんの素敵な男性と付き合ってきたんですよね？","ENG":"Nicole, you know so much about relationships. I bet you've gone out with many great men.","TWN":"妮可，你好像戀愛高手喔，你跟很多帥氣的男人交往過吧？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아, 아뇨! 절대 그렇진 않아요!","JPN":"い、いいえ！　それはないです！","ENG":"Oh, no. I have not.","TWN":"沒…沒有！絕對沒有！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"에이, 괜찮아요. 진심으로 부러워서 그러는 거니까요.","JPN":"いや、否定しなくていいですよ。羨ましくて言ってるだけなので。","ENG":"Come on, you can be honest with me. I'm genuinely envious of you.","TWN":"哎唷～有什麼關係～我是真的很羨慕才這麼說的。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"저처럼 평범한 사람은 고독한 재벌 2세나 전교회장 출신의 보디가드 같은 남자와 사귈 기회가 거의 없거든요.","JPN":"私みたいに平凡な人間は孤独な財閥2世や\\n生徒会長をしていたボディーガードのような男性と付き合う機会なんか、ほぼありませんよ。","ENG":"Ordinary girls like me never get a chance to go out with rich heirs or ex-Navy SEAL bodyguards.","TWN":"像我這種平凡的女生，怎麼可能有機會跟孤傲的富二代，或是以前是學校風雲人物的保鑣交往呢？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아, 사실 그건 제가 직접 겪은 일이 아니라…….","JPN":"えっと、それはですね、私が実際に経験したことじゃなく……","ENG":"Oh, actually, I didn't—","TWN":"那個…其實都不是我的親身經歷啦……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그렇지? 니콜 양은 이런 쪽에는 완전 전문가라니까?","JPN":"そうでしょ？　ニコルちゃんはこっち系に関してはスペシャリストなの！","ENG":"I know. Nicole is an expert at this, right?","TWN":"是不是！就說我們妮可是這方面的專家！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_GLASS_SURVE"},{"id":"L37_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"네! 이런 분이 바텐더로 계시는 게 이상할 정도예요!","JPN":"はい！　こんな方がバーテンダーとして働いているなんてもったいないくらいです！","ENG":"Yes! It's strange she's here bartending.","TWN":"真的！戀愛專家怎麼會來當調酒師呢？！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"연애의 산전수전을 모두 겪어본 바텐더라니~ 그건 그것대로 낭만적이긴 하지만요.","JPN":"恋愛経験が豊富なバーテンダーだなんて、それはそれであこがれちゃいますが。","ENG":"A bartender who's so experienced in love! That's romantic in a way, I guess.","TWN":"難道是經歷過愛情千瘡百孔的調酒師嗎～聽起來也是滿爛漫的～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"궁금한 게 있으면 언제든 상담하러 와도 좋아.","JPN":"気になることがあればいつでも相談に来てね。","ENG":"If you want to talk, you can come here anytime.","TWN":"有什麼戀愛上的問題，歡迎隨時光臨～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GUEST_VOICE_WOMEN_NULL","text":{"KOREA":"정말이요? 자주 올게요!","JPN":"本当ですか？　絶対にまた来ます！","ENG":"Really? Okay!","TWN":"真的嗎？我會常來的！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"저, 정말 이래도 괜찮은 건가요?","JPN":"ほ、本当にこれでいいんですか？","ENG":"Erm, are you sure this is okay?","TWN":"這…這樣真的沒問題嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"얼떨결에 지난번에 본 순정만화 얘길 꺼내긴 했지만… 전 진짜로 사귀어 본 적도 없는데.","JPN":"ついこの前読んだ少女漫画の話を切り出しましたが……\\n実際は本当につき合ったこともないのに。","ENG":"What she thinks I've experienced is just the romance comics I read the last time... I've never gone out with anyone.","TWN":"我只是把看過的少女漫畫內容來出來講…但我又沒有真正的交往過。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그래?","JPN":"そう？","ENG":"Oh, yeah?","TWN":"是嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"연애 상담이 부담스럽다면 어쩔 수 없지. 그 손님에겐 내가 잘 말해 둘게.","JPN":"恋愛相談が負担になるなら仕方ないわね。\\nあのお客さんにはアタシがうまく言っておくわ。","ENG":"If you don't feel comfortable talking to people about love, I won't force you. I'll talk to her next time.","TWN":"如果你覺得愛戀諮商很有壓力，那我會親自去跟客人解釋。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"아뇨. 딱히 부담스러운 건 아니지만… 거짓말하는 것 같아서 죄책감이 들어요.","JPN":"いや、別に負担ではないのですが……\\n嘘をついているようで、罪悪感を感じてしまうんです。","ENG":"No, I don't mind talking about it, but... I feel as if I'm lying to them.","TWN":"不…我不覺得有壓力…只是感覺像在說謊，覺得有點罪惡感。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그냥 위로만 해 줄 뿐이야. 가능성이 없는 헛된 조언을 해주는 것도 아니잖아?","JPN":"ただ慰めてあげるだけよ。\\nできっこない無駄なアドバイスをしているわけでもないでしょ？","ENG":"No. You're trying to comfort them. It's not like you're giving them completely unrealistic advice, either. Is it?","TWN":"你只是在安慰她，又沒有給她不切實際的建議不是嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"네?","JPN":"はい？","ENG":"Huh?","TWN":"嗯？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"사람들은 자기보다 우월한 사람에게 <color=#ffd34c>너는 잘못하지 않았다</color>고 위로 받고 싶어 하는 법이거든.","JPN":"人は自分より優れた人に<color=#ffd34c>あなたは間違っていない</color>と慰められたがるものなの。","ENG":"People want to be told by someone who's better than them that <color=#ffd34c>they didn't do anything wrong</color>.","TWN":"人都會想從比自己厲害的人身上聽到<color=#ffd34c>你沒有做錯什麼</color>這種話，來尋求安慰。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"그런 면에서 생판 연애를 모르는 사람보단 사랑 전문가에게 받는 위로가 훨씬 효과적이지.","JPN":"だから、全く恋愛を知らない人よりも愛の専門家から受ける慰めのほうがずっと効果的よ。","ENG":"In that sense, they feel better when they talk to someone who knows a lot about love than someone who doesn't.","TWN":"所以，比起母胎單身的人，戀愛專家給的安慰一定更有效吧！"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"니콜 양도 그렇게 생각하지 않아?","JPN":"ニコルちゃんもそう思わない？","ENG":"Don't you agree, Nicole?","TWN":"你不這麼認為嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그렇군요. 이런 게 바로 새하얀 거짓말이라는 거죠?","JPN":"なるほど。これがまさに、真っ白な嘘ということですね？","ENG":"I see. This is what they call a white lie, isn't it?","TWN":"原來如此，這就是所謂的善意的謊言嗎？"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"거짓말에 색깔은 상관없어. 네 행동에서 중요한 건 평가하는 사람이 아닌 자기 의지니까.","JPN":"嘘に色なんて関係ないわ。\\nあなたの行動で大事なのは、評価する人ではなく自身の意思なんだから。","ENG":"It doesn't matter what color your lie is or what others think of it. What matters is what you think of it.","TWN":"謊言無關善意或惡意，因為最重要的不是其他人怎麼想，而是你怎麼想。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"네가 진심으로 옳다고 생각하면, 그걸로 충분한 거야.","JPN":"あなたが心から正しいと思ったなら、それで十分よ。","ENG":"If you think it's the right thing to do, then it is.","TWN":"若你真心覺得這是對的，這個理由就已經很充分。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"BARTENDER_BAR_NULL_NULL","text":{"KOREA":"그레모리 씨는 정말 좋으신 분이네요.","JPN":"グレモリーさんは本当にいい方ですね。","ENG":"Gremory, you're so kind.","TWN":"葛茉莉，你真是個好人。"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"GREMORY_BAR_NULL_NULL","text":{"KOREA":"어머, 고마워. 나도 니콜 양처럼 순수한 사람이 좋더라.","JPN":"あら、ありがとう。アタシもニコルちゃんのようにピュアな人が好きよ。","ENG":"Oh, thanks. I like pure-hearted people like you, too, Nicole.","TWN":"哇喔，謝謝你，我也很喜歡像你這麼單純的人喔～"},"stage":{"bg":"GREMORY_BAR","bgm":"THEMA_GREMORY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BARTENDER_BAR_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"GREMORY_BAR_NULL_NULL","face":"UNIT_LAUGH"}}}}]`);export{e as default};